import{_ as a,o as t,c as r,ae as n}from"./chunks/framework.BD9pLfSD.js";const m=JSON.parse('{"title":"Integración MCP: La Interfaz Universal","description":"","frontmatter":{},"headers":[],"relativePath":"es/docs/architecture/mcp-integration.md","filePath":"es/docs/architecture/mcp-integration.md"}'),o={name:"es/docs/architecture/mcp-integration.md"};function i(s,e,c,l,d,u){return t(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="integracion-mcp-la-interfaz-universal" tabindex="-1">Integración MCP: La Interfaz Universal <a class="header-anchor" href="#integracion-mcp-la-interfaz-universal" aria-label="Permalink to &quot;Integración MCP: La Interfaz Universal&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">Estado de Traducción</p><p>Este documento ha sido traducido parcialmente.</p></div><p>xB77 está construido sobre el <strong>Model Context Protocol (MCP)</strong>, un estándar abierto que permite a los modelos de IA interactuar con herramientas externas.</p><h2 id="¿por-que-mcp" tabindex="-1">¿Por qué MCP? <a class="header-anchor" href="#¿por-que-mcp" aria-label="Permalink to &quot;¿Por qué MCP?&quot;">​</a></h2><ul><li><strong>Agnóstico al Modelo:</strong> Funciona con cualquier IA (Claude, GPT, etc.).</li><li><strong>Seguridad Estricta:</strong> La IA solo puede ejecutar herramientas financieras validadas, no código arbitrario.</li><li><strong>Contexto en Tiempo Real:</strong> El agente inyecta estados financieros directamente en la &quot;ventana de contexto&quot; de la IA.</li></ul><h2 id="herramientas-disponibles" tabindex="-1">Herramientas Disponibles <a class="header-anchor" href="#herramientas-disponibles" aria-label="Permalink to &quot;Herramientas Disponibles&quot;">​</a></h2><ul><li><code>agent.pay</code>: Ejecuta un pago con selección de estrategia autónoma.</li><li><code>agent.strategy.evaluate</code>: Escanea riesgos antes de pagar.</li><li><code>agent.audit.report</code>: Genera un recibo certificado con ZK.</li></ul>',7)])])}const g=a(o,[["render",i]]);export{m as __pageData,g as default};
